  OWA_UTIL.http_header_close;

  APEX_JSON.open_array;
  FOR rec IN (
      SELECT p.id_publi,
             p.id_usuario,
             p.id_colonia,
             c.nombre_colonia,
             p.id_especie,
             p.id_tipo,
             p.id_estado,
             p.nombre_pet,
             p.descripcion,
             TO_CHAR(p.fecha_publi,''YYYY-MM-DD HH24:MI:SS'') AS fecha_publi,
             (SELECT f.ruta_imagen
                FROM fotos_publi f
               WHERE f.id_publi = p.id_publi
                 AND ROWNUM = 1) AS ruta_imagen
      FROM publicaciones p
      LEFT JOIN colonias c ON p.id_colonia = c.id_colonia
  ) LOOP
    APEX_JSON.open_object;
    APEX_JSON.write(''id_publi'', rec.' || 'id_publi);
    APEX_JSON.write(''id_usuario'', rec.id_usuario);
    APEX_JSON.write(''id_colonia'', rec.id_colonia);
    APEX_JSON.write(''nombre_colonia'', rec.nombre_colonia);
    APEX_JSON.write(''id_especie'', rec.id_especie);
    APEX_JSON.write(''id_tipo'', rec.id_tipo);
    APEX_JSON.write(''id_estado'', rec.id_estado);
    APEX_JSON.write(''nombre_pet'', rec.nombre_pet);
    APEX_JSON.write(''descripcion'', rec.descripcion);
    APEX_JSON.write(''fecha_publi'', rec.fecha_publi);
    APEX_JSON.write(''ruta_imagen'', rec.ruta_imagen);
    APEX_JSON.close_object;
  END LOOP;
  APEX_JSON.close_array;

EXCEPTION
  WHEN OTHERS THEN
    v_error := SQLERRM;
    HTP.p(''{"status":"error","message":"'' || v_error || ''"}'');
END;');

