'DECLARE
  v_id_publi NUMBER;
BEGIN
  OWA_UTIL.mime_header(''application/json'', FALSE);
  OWA_UTIL.http_header_close;

  INSERT INTO publicaciones (
    id_usuario,
    id_colonia,
    id_especie,
    id_tipo,
    id_estado,
    nombre_pet,
    descripcion,
    fecha_publi
  ) VALUES (
    :id_usuario,
    :id_colonia,
    :id_especie,
    :id_tipo,
    1,
    :nombre_pet,
    :descripcion,
    SYSDATE
  )
  RETURNING id_publi INTO v_id_publi;

  APEX_JSON.open_object;
  APEX_JSON.write(''status'', ''success'');
  APEX_JSON.write(''id_publi'', v_id_publi);
  APEX_JSON.write(''message'', ''Publicación creada correctamente'');
  APEX_JSON.close_object;
EXCEPTION
  WHEN OTHERS THEN
    APEX_JSON.open_object;
    APEX_JSON.write(''status'', ''error'');
    APEX_JSON.write(''message'', SQLERRM);
    APEX_JSON.close_object;
END;');

